<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatActionResolver;use App\Domain\Combat\CombatActionType;use App\Domain\Combat\CombatSide;use App\Domain\Combat\CombatStateStatus;use App\Domain\Combat\CombatTurnOrder;use App\Domain\Combat\Data\CombatCommand;use App\Domain\Combat\Data\CombatParticipantState;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatantStats;use App\Domain\Random\RandomNumberGenerator;use PHPUnit\Framework\TestCase;class ResolverRandom implements RandomNumberGenerator{private $v;public function __construct($v){$this->v=$v;}public function randomInt(int $a,int $b):int{return array_shift($this->v);}}class CombatActionResolverTest extends TestCase{private function p($id,$side,$pos,$hp=20,$attack=5,$speed=1){return new CombatParticipantState(new CombatantStats($id,$id,20,$hp,$attack,0,5,0,0,1.5,$speed,0),$hp,$side,$pos);}public function test_multi_participant_action_and_ally_rejection(){$ps=[$this->p('p1',CombatSide::PLAYERS,1),$this->p('p2',CombatSide::PLAYERS,2),$this->p('e1',CombatSide::ENEMIES,1),$this->p('e2',CombatSide::ENEMIES,2)];$order=(new CombatTurnOrder())->build($ps);$state=new CombatState($ps,1,$order,0,CombatStateStatus::IN_PROGRESS);$resolver=new CombatActionResolver(new ResolverRandom([1,10000]),new CombatTurnOrder());$step=$resolver->resolve($state,new CombatCommand(null,'p1',CombatActionType::BASIC_ATTACK,'e1'));$this->assertSame(15,$step->nextState()->participant('e1')->currentHealth());$this->assertSame(20,$step->nextState()->participant('e2')->currentHealth());$this->expectException(\InvalidArgumentException::class);$resolver->resolve($state,new CombatCommand(null,'p1',CombatActionType::BASIC_ATTACK,'p2'));}}
